diff --git a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
index d824c40c401d..b4bce313f8a4 100644
--- a/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
+++ b/llvm/lib/Transforms/Vectorize/SLPVectorizer.cpp
@@ -9760,6 +9760,8 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
         -> std::optional<TTI::ShuffleKind> {
       if (NumElts <= EltsPerVector)
         return std::nullopt;
+      unsigned AlignedNumElts = alignTo(NumElts, EltsPerVector);
+      unsigned MaxIdx = AlignedNumElts - EltsPerVector;
       int OffsetReg0 =
           alignDown(std::accumulate(Mask.begin(), Mask.end(), INT_MAX,
                                     [](int S, int I) {
@@ -9773,7 +9775,10 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
       // Check that if trying to permute same single/2 input vectors.
       TTI::ShuffleKind ShuffleKind = TTI::SK_PermuteSingleSrc;
       int FirstRegId = -1;
-      Indices.assign(1, OffsetReg0);
+      unsigned Idx0 = OffsetReg0 % NumElts;
+      if (Idx0 > MaxIdx)
+        return std::nullopt;
+      Indices.assign(1, Idx0);
       for (auto [Pos, I] : enumerate(Mask)) {
         if (I == PoisonMaskElem)
           continue;
@@ -9801,7 +9806,10 @@ class BoUpSLP::ShuffleCostEstimator : public BaseShuffleAnalysis {
                       return std::min(S, I);
                     }),
                 EltsPerVector);
-            Indices.push_back(OffsetReg1 % NumElts);
+            unsigned Idx1 = OffsetReg1 % NumElts;
+            if (Idx1 > MaxIdx)
+              return std::nullopt;
+            Indices.push_back(Idx1);
           }
           Idx = I - OffsetReg1;
         }

